    } else if (args[i] === '--max' && args[i + 1]) {
      maxIterations = parseInt(args[i + 1]);
    } else if (args[i] === '--no-push') {
      autoPush = false;
    } else if (args[i] === '--enable-dashboard') {
      enableDashboard = true;
    } else if (args[i] === '--disable-dashboard') {
      enableDashboard = false;
    }
  }

  // 启动 Dashboard
  if (enableDashboard) {
    try {
      const dashboardUrl = await startDashboard({
        port: 3000,
        host: '0.0.0.0'
      });
      console.log(`\n✅ Web Dashboard 已启动: ${dashboardUrl}`);
      console.log(`📊 打开浏览器查看: http://localhost:3000\n`);
    } catch (error) {
      console.error('❌ Dashboard 启动失败:', error);
      console.log('⚠️  继续运行，但无监控界面\n');
    }
  }

  // 启动自动迭代
  const engine = new AutoIterationEngine({
    projectPath: process.cwd(),
    intervalMs: intervalSec * 1000,
    maxIterations,
    autoCommit: true,
    autoPush,
    permissionMode: 'bypassPermissions'
  });

  await engine.start();
}
