import { defineStore } from 'pinia';
import { ref, computed } from 'vue';
import { iterationAPI } from '@/api';

export const useIterationStore = defineStore('iteration', () => {
  const iterations = ref<any[]>([]);
  const currentIteration = ref<any | null>(null);
  const loading = ref(false);
  const total = ref(0);

  // 获取列表
  async function fetchIterations(params: any = {}) {
    loading.value = true;
    try {
      const response = await iterationAPI.list(params);
      iterations.value = response.data.items;
      total.value = response.data.total;
    } finally {
      loading.value = false;
    }
  }

  // 获取当前迭代
  async function fetchCurrentIteration() {
    try {
      const response = await iterationAPI.current();
      currentIteration.value = response.data;
    } catch (error) {
      currentIteration.value = null;
    }
  }

  // WebSocket 更新
  function updateIteration(iteration: any) {
    const index = iterations.value.findIndex(i => i.id === iteration.id);
    if (index !== -1) {
      iterations.value[index] = iteration;
    } else {
      iterations.value.unshift(iteration);
    }
  }

  function updateProgress(id: string, progress: number) {
    const iteration = iterations.value.find(i => i.id === id);
    if (iteration) {
      iteration.progress = progress;
    }
    if (currentIteration.value?.id === id) {
      currentIteration.value.progress = progress;
    }
  }

  return {
    iterations,
    currentIteration,
    loading,
    total,
    fetchIterations,
    fetchCurrentIteration,
    updateIteration,
    updateProgress
  };
});
